-- ============================================================
-- CareMatch360 — Seed 002: 200 Providers + 40 Clients
-- Maryland, 10 counties, real addresses + coordinates
-- Run AFTER migration_001.sql
-- Safe to re-run: deletes seed data first
-- ============================================================

-- Clear previous seed data (leaves any records you manually added)
DELETE FROM case_matches;
DELETE FROM cases;
DELETE FROM clients WHERE notes LIKE 'Client in %';
DELETE FROM providers WHERE notes LIKE 'Based in %';



-- Verify counts
SELECT credential_type, COUNT(*) as total,
       SUM(CASE WHEN available THEN 1 ELSE 0 END) as available_count
FROM providers
GROUP BY credential_type ORDER BY total DESC;

SELECT urgency_level, COUNT(*) as total FROM clients GROUP BY urgency_level;

SELECT p.notes as county, COUNT(*) as providers FROM providers p GROUP BY p.notes ORDER BY providers DESC;
